export const getMockDataForTemplate = (templateId, categoryId, t) => {
    // If no specific category is selected, we fallback to general
    const cat = categoryId || 'general';
    let hash = 0;
    for (let i = 0; i < templateId.length; i++) {
        hash = templateId.charCodeAt(i) + ((hash << 5) - hash);
    }
    const index = Math.abs(hash) % 10;
    
    const categoryMocks = MOCK_DATA[cat] || MOCK_DATA['general'];
    const mock = categoryMocks[index];

    // If t is provided (from useTranslation), we dynamically translate the mock content
    if (t) {
        const translatedCat = t(`templates.styles.${cat}`, { defaultValue: cat });
        
        return {
            ...mock,
            personalInfo: {
                ...mock.personalInfo,
                summary: t('mock.summary', { industry: translatedCat, defaultValue: mock.personalInfo.summary }),
                location: t('mock.location', { defaultValue: mock.personalInfo.location })
            },
            experience: mock.experience.map(exp => ({
                ...exp,
                company: t('mock.company', { defaultValue: exp.company }),
                endDate: t('mock.present', { defaultValue: exp.endDate }),
                description: t('mock.exp_desc', { industry: translatedCat, defaultValue: exp.description })
            })),
            education: mock.education.map(edu => ({
                ...edu,
                degree: t('mock.degree', { industry: translatedCat, defaultValue: edu.degree }),
                institution: t('mock.university', { defaultValue: edu.institution })
            })),
            skills: mock.skills.map(skill => {
                const key = skill.toLowerCase().replace(/\s+/g, '');
                return t(`mock.skills.${key}`, { defaultValue: skill });
            }),
            languages: mock.languages.map(lang => ({
                ...lang,
                language: t(`mock.languages.${lang.language.toLowerCase()}`, { defaultValue: lang.language }),
                level: t(`mock.languages.${lang.level.toLowerCase()}`, { defaultValue: lang.level })
            }))
        };
    }

    return mock;
};
